INSERT INTO questions (number, question, image, answer, group_id, user_id) VALUES 
(1, '¿Qué es la Demografía?', NULL, 'Es el estudio estadístico de las poblaciones humanas, incluyendo su tamaño, estructura, distribución y cambios a lo largo del tiempo.', 1, 1),
(2, 'Define la Tasa de Mortalidad Infantil.', NULL, 'Es el número de defunciones de niños menores de un año por cada 1000 nacidos vivos en un área y período determinados.', 1, 1),
(3, 'Nombra las tres medidas de tendencia central más comunes.', NULL, 'Media aritmética, Mediana y Moda.', 1, 1),
(4, '¿Qué son las fuentes primarias y secundarias de recolección de información?', NULL, 'Las primarias son datos obtenidos directamente por el investigador (ej. observación, encuesta); las secundarias son datos ya existentes recopilados por otros (ej. registros, censos).', 1, 1),
(5, 'Menciona dos medidas de dispersión comunes.', NULL, 'Rango, Varianza, Desviación Estándar y Coeficiente de Variación.', 1, 1),
(6, 'Define Tasa en el contexto de estadísticas de salud.', NULL, 'Es una medida de frecuencia de un evento (ej. enfermedad, muerte) en una población durante un período específico, usualmente multiplicada por una potencia de 10 (ej. por 1000 habitantes).', 1, 1),
(7, '¿Qué nos indican las medidas de dispersión?', NULL, 'Indican cuán esparcidos o variables están los datos respecto a una medida central, generalmente la media.', 1, 1),
(8, '¿Qué representa la frecuencia absoluta en una distribución de frecuencias?', NULL, 'Es el número de veces que aparece un determinado valor o que los datos caen dentro de un intervalo de clase específico.', 1, 1),
(9, '¿Cuál medida de tendencia central divide al conjunto de datos ordenados en dos partes iguales?', NULL, 'La Mediana.', 1, 1),
(10, 'Dentro de las variables cuantitativas, ¿qué diferencia hay entre discretas y continuas?', NULL, 'Las discretas toman valores enteros, usualmente de conteos (ej. número de hijos), mientras que las continuas pueden tomar cualquier valor en un intervalo, usualmente de mediciones (ej. peso, altura).', 1, 1),
(11, '¿Qué es una Proporción y un Porcentaje?', NULL, 'Una Proporción es una fracción donde el numerador es parte del denominador (parte/total); un Porcentaje es una proporción multiplicada por 100.', 1, 1),
(12, '¿Qué diferencia hay entre la tasa bruta de mortalidad y la tasa neta (o específica) de mortalidad?', NULL, 'La tasa bruta mide las muertes totales en relación a la población total, mientras que la tasa neta (o específica) mide las muertes en relación a un subgrupo específico de la población (ej. por edad, sexo o causa).', 1, 1);
INSERT INTO questions (number, question, image, answer, group_id, user_id) VALUES 
(13, 'Nombra las cuatro etapas principales del método estadístico.', NULL, 'Planificación, Recolección, Procesamiento y Análisis.', 2, 1),
(14, '¿Qué información visual proporciona una pirámide de población?', NULL, 'Muestra la estructura de una población por edad y sexo en un momento determinado, permitiendo inferir características demográficas como tasas de natalidad y mortalidad.', 2, 1),
(15, 'Menciona las dos grandes ramas de la Estadística.', NULL, 'Estadística Descriptiva y Estadística Inferencial.', 2, 1),
(16, 'Define Razón e Índice como medidas para resumir datos cualitativos.', NULL, 'La Razón compara dos cantidades donde el numerador no está incluido en el denominador (ej. razón hombres/mujeres). El Índice es una razón multiplicada por 100, usada a menudo para comparaciones.', 2, 1),
(17, '¿Cuál es la diferencia principal entre Estadística Descriptiva e Inferencial?', NULL, 'La Descriptiva resume y organiza datos existentes, mientras que la Inferencial saca conclusiones sobre una población basándose en una muestra.', 2, 1),
(18, '¿Qué mide la Letalidad de una enfermedad?', NULL, 'Mide la proporción de personas diagnosticadas con una enfermedad que mueren a causa de ella en un período específico. Indica la gravedad de la enfermedad.', 2, 1),
(19, '¿Para qué se utiliza el Coeficiente de Variación (CV)?', NULL, 'Se utiliza para comparar la dispersión relativa entre dos o más conjuntos de datos que pueden tener diferentes unidades o medias.', 2, 1),
(20, 'Define frecuencia relativa y frecuencia acumulada.', NULL, 'La frecuencia relativa es la proporción o porcentaje de veces que ocurre un valor o clase; la frecuencia acumulada es la suma de las frecuencias (absolutas o relativas) hasta una clase o valor determinado.', 2, 1),
(21, 'Menciona dos procedimientos para recolectar información según su frecuencia.', NULL, 'Encuesta (puntual o periódica a una muestra), Registro (continuo) y Censo (periódico a toda la población).', 2, 1),
(22, 'Explica brevemente qué miden la Sensibilidad y la Especificidad de una prueba diagnóstica.', NULL, 'La Sensibilidad mide la capacidad de la prueba para detectar correctamente a los enfermos (verdaderos positivos). La Especificidad mide la capacidad para identificar correctamente a los sanos (verdaderos negativos).', 2, 1),
(23, '¿Cómo se clasifican las variables según su naturaleza?', NULL, 'Se clasifican en Cualitativas (expresan cualidades o categorías) y Cuantitativas (expresan cantidades numéricas).', 2, 1),
(24, '¿Qué es la Estadística?', NULL, 'Es la ciencia que se ocupa de la recolección, organización, análisis e interpretación de datos para la toma de decisiones.', 2, 1);
INSERT INTO questions (number, question, image, answer, group_id, user_id) VALUES 
(25, '¿Qué es una distribución de frecuencias?', NULL, 'Es una tabla o gráfico que muestra cuántas veces ocurre cada valor o categoría de una variable en un conjunto de datos.', 3, 1),
(26, 'Nombra dos tipos de estadísticas vitales fundamentales en salud pública.', NULL, 'Estadísticas de Natalidad (nacimientos) y Estadísticas de Mortalidad (defunciones).', 3, 1),
(27, 'Menciona un indicador que mida la disponibilidad de recursos humanos en salud.', NULL, 'Número de médicos por cada 10,000 habitantes o número de enfermeras por cama hospitalaria.', 3, 1),
(28, '¿Cuál es la diferencia entre Incidencia y Prevalencia en morbilidad?', NULL, 'La Incidencia mide la frecuencia de *nuevos* casos de una enfermedad en un período, mientras que la Prevalencia mide la proporción de casos *existentes* (nuevos y antiguos) en un punto o período.', 3, 1),
(29, 'En una distribución de frecuencias por intervalos, ¿qué es el límite inferior y el límite superior de una clase?', NULL, 'Son los valores mínimo y máximo que definen el rango de cada intervalo o clase.', 3, 1),
(30, 'Según el criterio de la ONU de 1989 mencionado, ¿a partir de qué edad se analiza la población para clasificarla según su grado de envejecimiento?', NULL, 'Se analiza la población de 65 años en adelante.', 3, 1),
(31, 'Da un ejemplo de un indicador que mida el aprovechamiento de los recursos en salud.', NULL, 'La Tasa de Ocupación Hospitalaria (porcentaje de camas ocupadas) o el Promedio de Estadía Hospitalaria.', 3, 1),
(32, 'Dentro de las variables cualitativas, ¿qué diferencia hay entre nominales y ordinales?', NULL, 'Las nominales son categorías sin orden inherente (ej. sexo, grupo sanguíneo), mientras que las ordinales tienen un orden o jerarquía (ej. nivel educativo, grado de satisfacción).', 3, 1),
(33, '¿Cuál es la diferencia fundamental entre una encuesta y un censo?', NULL, 'La encuesta se aplica a una muestra representativa de la población, mientras que el censo busca incluir a todos los miembros de la población.', 3, 1),
(34, 'Menciona algunos errores comunes al diseñar un formulario de recolección de datos.', NULL, 'Preguntas ambiguas, opciones de respuesta no exhaustivas o no excluyentes, o preguntas irrelevantes para los objetivos, falta de ética.', 3, 1),
(35, '¿Qué medida de tendencia central representa el valor más frecuente en un conjunto de datos?', NULL, 'La Moda.', 3, 1),
(36, '¿Qué son los cuartiles?', NULL, 'Son medidas de posición que dividen un conjunto de datos ordenados en cuatro partes iguales. Hay tres cuartiles: Q1, Q2 (Mediana) y Q3.', 3, 1);